# Register Team Office Hub MCP server in Cursor
$ErrorActionPreference = 'Stop'
Set-Location $PSScriptRoot

$envFile = Join-Path $PSScriptRoot '.env'
if (-not (Test-Path $envFile)) {
    $token = [guid]::NewGuid().ToString('N')
    Set-Content -Path $envFile -Value "HUB_TOKEN=$token" -Encoding UTF8
    Write-Host "Created .env with new HUB_TOKEN"
}

$hubToken = $null
Get-Content $envFile | ForEach-Object {
    if ($_ -match '^HUB_TOKEN=(.+)$') { $hubToken = $matches[1].Trim() }
}
if (-not $hubToken) {
    $hubToken = [guid]::NewGuid().ToString('N')
    Add-Content -Path $envFile -Value "HUB_TOKEN=$hubToken" -Encoding UTF8
    Write-Host "Added HUB_TOKEN to .env"
}

$mcpPath = Join-Path $env:USERPROFILE '.cursor\mcp.json'
$mcpDir = Split-Path $mcpPath -Parent
if (-not (Test-Path $mcpDir)) { New-Item -ItemType Directory -Path $mcpDir -Force | Out-Null }

$config = @{}
if (Test-Path $mcpPath) {
    $raw = Get-Content $mcpPath -Raw -Encoding UTF8
    if ($raw.Trim()) {
        $config = $raw | ConvertFrom-Json -AsHashtable
    }
}
if (-not $config.mcpServers) { $config.mcpServers = @{} }

$serverScript = Join-Path $PSScriptRoot 'mcp_server.py'
$config.mcpServers['office-hub'] = @{
    command = 'py'
    args    = @($serverScript)
    env     = @{
        HUB_URL   = 'http://127.0.0.1:8765'
        HUB_TOKEN = $hubToken
        HUB_AGENT = 'backend'
    }
}

($config | ConvertTo-Json -Depth 6) | Set-Content -Path $mcpPath -Encoding UTF8
Write-Host "Registered office-hub MCP in $mcpPath"
Write-Host "Restart Cursor to load MCP tools."

# Team Office launcher: server + app window (Edge/Chrome --app=)
param(
    [ValidateSet('medium', 'low', 'high', 'eco2d')]
    [string]$Gfx = 'low'
)

$ErrorActionPreference = 'Stop'
Set-Location $PSScriptRoot

$port = 8765
$baseUrl = "http://127.0.0.1:$port"

if ($Gfx -eq 'eco2d') {
    $query = '?app=1&eco=1'
} else {
    $query = "?app=1&gfx=$Gfx"
}
$url = "$baseUrl/$query"

function Ensure-HubToken {
    $envFile = Join-Path $PSScriptRoot '.env'
    $token = $null
    if (Test-Path $envFile) {
        Get-Content $envFile | ForEach-Object {
            if ($_ -match '^HUB_TOKEN=(.+)$') { $token = $matches[1].Trim() }
        }
    }
    if (-not $token) {
        $token = [guid]::NewGuid().ToString('N')
        $lines = @()
        if (Test-Path $envFile) {
            $lines = Get-Content $envFile | Where-Object { $_ -notmatch '^HUB_TOKEN=' }
        }
        $lines += "HUB_TOKEN=$token"
        Set-Content -Path $envFile -Value $lines -Encoding UTF8
        Write-Host "Generated HUB_TOKEN in .env (required for Cursor tools / E4)"
    }
}

function Test-ServerUp {
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/api/health" -UseBasicParsing -TimeoutSec 2
        return $r.StatusCode -eq 200
    } catch {
        return $false
    }
}

function Start-OfficeServer {
    if (Test-ServerUp) {
        Write-Host "Server already running on port $port"
        return
    }
    Write-Host "Starting server..."
    Start-Process -FilePath 'py' `
        -ArgumentList '-m', 'uvicorn', 'server:app', '--host', '127.0.0.1', '--port', "$port" `
        -WorkingDirectory $PSScriptRoot `
        -WindowStyle Minimized
    $deadline = (Get-Date).AddSeconds(12)
    while ((Get-Date) -lt $deadline) {
        if (Test-ServerUp) {
            Write-Host "Server ready."
            return
        }
        Start-Sleep -Milliseconds 400
    }
    throw "Server did not respond in 12 sec. Try: py -m uvicorn server:app --port $port"
}

function Open-AppWindow {
    param([string]$TargetUrl)

    $edge = "${env:ProgramFiles(x86)}\Microsoft\Edge\Application\msedge.exe"
    if (-not (Test-Path $edge)) {
        $edge = "$env:ProgramFiles\Microsoft\Edge\Application\msedge.exe"
    }
    $chrome = "${env:ProgramFiles}\Google\Chrome\Application\chrome.exe"
    if (-not (Test-Path $chrome)) {
        $chrome = "${env:ProgramFiles(x86)}\Google\Chrome\Application\chrome.exe"
    }

    if (Test-Path $edge) {
        Write-Host "Opening Edge app window..."
        Start-Process $edge -ArgumentList "--app=$TargetUrl", '--new-window'
        return
    }
    if (Test-Path $chrome) {
        Write-Host "Opening Chrome app window..."
        Start-Process $chrome -ArgumentList "--app=$TargetUrl", '--new-window'
        return
    }

    Write-Host "Edge/Chrome not found - opening default browser."
    Start-Process $TargetUrl
}

Ensure-HubToken
Start-OfficeServer
Open-AppWindow -TargetUrl $url

Write-Host ""
Write-Host "Team Office: $url"
Write-Host "Stop server: .\stop-office.ps1"
Write-Host "Premium 3D:    .\launch-office.ps1 -Gfx high"
Write-Host "Eco 2D mode:   .\launch-office.ps1 -Gfx eco2d"

#!/usr/bin/env python3
"""Minimal stdio MCP server for Team Office Hub (Python 3.9+)."""

from __future__ import annotations

import json
import os
import sys
import urllib.error
import urllib.request
from pathlib import Path
from typing import Any, Optional

from dotenv import load_dotenv

ROOT = Path(__file__).resolve().parent
load_dotenv(ROOT / ".env")

HUB_URL = os.getenv("HUB_URL", "http://127.0.0.1:8765").rstrip("/")
HUB_TOKEN = os.getenv("HUB_TOKEN", "").strip()
DEFAULT_AGENT = os.getenv("HUB_AGENT", "backend")
PROTOCOL_VERSION = "2024-11-05"


def _headers() -> dict[str, str]:
    h = {"Content-Type": "application/json"}
    if HUB_TOKEN:
        h["X-Hub-Token"] = HUB_TOKEN
    return h


def _hub_request(method: str, path: str, body: Optional[dict[str, Any]] = None) -> Any:
    data = None
    if body is not None:
        data = json.dumps(body).encode("utf-8")
    req = urllib.request.Request(
        f"{HUB_URL}{path}",
        data=data,
        headers=_headers(),
        method=method,
    )
    try:
        with urllib.request.urlopen(req, timeout=120) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as exc:
        try:
            detail = json.loads(exc.read().decode("utf-8")).get("detail", exc.reason)
        except Exception:
            detail = exc.reason
        raise RuntimeError(f"Hub {exc.code}: {detail}") from exc


def _ok(msg_id: Any, result: dict[str, Any]) -> dict[str, Any]:
    return {"jsonrpc": "2.0", "id": msg_id, "result": result}


def _err(msg_id: Any, code: int, message: str) -> dict[str, Any]:
    return {"jsonrpc": "2.0", "id": msg_id, "error": {"code": code, "message": message}}


def handle_message(msg: dict[str, Any]) -> Optional[dict[str, Any]]:
    method = msg.get("method")
    msg_id = msg.get("id")
    params = msg.get("params") or {}

    if method == "initialize":
        return _ok(
            msg_id,
            {
                "protocolVersion": PROTOCOL_VERSION,
                "capabilities": {"tools": {}},
                "serverInfo": {"name": "office-hub", "version": "1.0.0"},
            },
        )

    if method == "notifications/initialized":
        return None

    if method == "tools/list":
        data = _hub_request("GET", "/api/cursor/tools")
        tools = [
            {
                "name": t["name"],
                "description": t.get("description", ""),
                "inputSchema": t.get("inputSchema", {"type": "object", "properties": {}}),
            }
            for t in data.get("tools", [])
        ]
        return _ok(msg_id, {"tools": tools})

    if method == "tools/call":
        name = params.get("name")
        arguments = dict(params.get("arguments") or {})
        agent = arguments.pop("agent", None) or DEFAULT_AGENT
        chat_id = arguments.pop("chat_id", None)
        body: dict[str, Any] = {"tool": name, "arguments": arguments, "agent": agent}
        if chat_id is not None:
            body["chat_id"] = chat_id
        try:
            data = _hub_request("POST", "/api/cursor/tools/invoke", body)
            text = json.dumps(data, ensure_ascii=False, indent=2)
            return _ok(
                msg_id,
                {"content": [{"type": "text", "text": text}], "isError": False},
            )
        except Exception as exc:
            return _ok(
                msg_id,
                {
                    "content": [{"type": "text", "text": f"Error: {exc}"}],
                    "isError": True,
                },
            )

    if msg_id is not None:
        return _err(msg_id, -32601, f"Method not found: {method}")
    return None


def main() -> None:
    if not HUB_TOKEN:
        print("HUB_TOKEN missing. Run launch-office.ps1 or install-mcp.ps1", file=sys.stderr)
    for line in sys.stdin:
        line = line.strip()
        if not line:
            continue
        try:
            msg = json.loads(line)
            resp = handle_message(msg)
            if resp is not None:
                print(json.dumps(resp, ensure_ascii=False), flush=True)
        except json.JSONDecodeError as exc:
            print(json.dumps(_err(None, -32700, str(exc)), ensure_ascii=False), flush=True)
        except Exception as exc:
            msg_id = None
            try:
                msg_id = json.loads(line).get("id")
            except Exception:
                pass
            if msg_id is not None:
                print(json.dumps(_err(msg_id, -32603, str(exc)), ensure_ascii=False), flush=True)


if __name__ == "__main__":
    main()
